package.sql:

  DECLARE
    v_patient_key NUMBER;
  BEGIN
    v_patient_key := sp_mapper.put_patient(
                        @MSH.MESSAGE_TYPE, -- event_type
                        @PID.PATIENT_ID, -- patient_id
                        @MRG.MERGEE_PATIENT_ID, -- prior_patient_id
                        @PID.ID_ISSUER_CODE, -- patient_id_issuer_code
                        @PID.SSN, -- ssn
                        @PID.FULL_NAME, -- full_name
                        @PID.FAMILY_NAME, -- last_name
                        @PID.GIVEN_NAME, -- first_name
                        @PID.MIDDLE_NAME, -- middle_name
                        @PID.PREFIX, -- prefix
                        @PID.SUFFIX, -- suffix
                        @PID.MARITAL_STATUS, -- marital_stat
                        @PID.CONFIDENTIALITY, -- confidentiality
                        @PID.DATE_OF_BIRTH, -- birth_dttm
                        @PID.DEATH_DTTM, -- death_dttm
                        @PID.ADMINISTRATIVE_SEX, -- sex
                        @PID.SIZE, -- size
                        @PID.WEIGHT, -- weight
                        @PID.BLOOD_TYPE_ABO, -- blood_type_abo
                        @PID.BLOOD_TYPE_RH, -- blood_type_rh
                        @PID.CITIZENSHIP, -- citizenship
                        @PID.OCCUPATION, -- occupation
                        @PID.RACE, -- race_code
                        @PID.PRIMARY_LANGUAGE, -- language_code
                        @PID.RELIGION, -- religion_code
                        @PID.BIRTH_PLACE, -- birthplace
                        @PID.MULTIPLE_BIRTH_INDICATOR, -- multiple_birth_status
                        @PID.BIRTH_ORDER, -- birth_order
                        @PID.EMAIL, -- email
                        @PID.PHONE_NUMBER_HOME, -- phone_no
                        @PID.PREGNANCY_CODE, -- pregnancy_code
                        @PID.PATIENT_STATUS, -- patient_stat
                        @PID.ACCOUNT_NUMBER, -- account_no
                        @PID.CONTACT_TYPE, -- contact_type
                        @PID.PHONE_NUMBER_HOME, -- home_phone_no
                        @PID.PHONE_NUMBER_BUSINESS, -- busi_phone_no
                        @PID.FAX_NUMBER, -- fax_no
                        @PID.ADDRESS, -- address
                        @PID.ADDRESS_CITY, -- city
                        @PID.ADDRESS_STATE, -- state
                        @PID.ADDRESS_COUNTRY, -- country
                        @PID.ADDRESS_ZIP_OR_POSTAL_CODE, -- zipcode
                        @PV1.VISIT_NUMBER, -- visit_number
                        @MSH.VISIT_STATUS, -- visit_stat
                        @PV1.ADMIT_DTTM, -- admit_dttm
                        @PV1.DISCHARGE_DTTM, -- discharge_dttm
                        @PV1.PATIENT_CLASS, -- patient_location
                        @PV1.ASSIGNED_PATIENT_LOCATION, -- patient_residence
                        @PV1.REFERRING_DOCTOR_ID, -- refer_doctor_id
                        @PV1.CONSULTING_DOCTOR_ID, -- consult_doctor_id
                        @PID.INSTITUTION_CODE, -- institution_code
                        @PV1.VISIT_COMMENT, -- visit_comment
                        @PID.ADMIT_ROUTE, -- admit_route
                        @PID.LASTMEN_STRUAL_DTTM, -- lastmen_strual_dttm
                        @PID.PREGNANCY_STATUS, -- pregnancy_status
                        @PID.CODE_ABBREVIATION, -- code_abbreviation
                        @PID.STATION_CODE, -- station_code
                        @PID.ENGLISH_NAME, -- english_name
                        @PID.ETHNIC_GROUP, -- ethnic_group
                        @PV1.ASSIGNED_PATIENT_LOCATION_FACILITY, -- current_department
                        @PV1.REFERRING_DOCTOR_NAME, -- refer_doctor_name
                        @PV1.CONSULTING_DOCTOR_NAME, -- consult_doctor_name
                        null, -- broker_aetitle
                        'HL7-PACS' -- broker_type
                      );
  END;


  DECLARE
    v_user_key NUMBER;
  BEGIN
    v_user_key := sp_mapper.put_user(
                    @STF.STAFF_ID_CODE, -- user_id
                    @STF.STAFF_NAME, -- user_name
                    @STF.STAFF_PASSWORD, -- password
                    @STF.STAFF_TYPE, -- user_level
                    @STF.ACTIVE_INACTIVE_FLAG, -- user_status
                    null -- comments
                  );
  END;

      
        DECLARE
          v_study_key NUMBER;
          v_idx NUMBER := 1;
          v_msps VARCHAR2(1000);
          v_msps_key NUMBER;
          v_reqproc_code_value VARCHAR2(32);
          v_reqproc_code_scheme VARCHAR2(32);
          v_sps_id VARCHAR2(32);
          v_modality VARCHAR2(8);
          v_sps_start_dttm VARCHAR2(8);
          v_protcode_value VARCHAR2(100);
          v_protcode_scheme VARCHAR2(100);
          v_protcode_meaning VARCHAR2(100);
          v_prior_sps_id VARCHAR2(32);
          v_regex_repeat_pattern VARCHAR2(32);
          v_regex_field_pattern VARCHAR2(32);
        BEGIN
          v_study_key := sp_mapper.put_order(
                            @MSH.MESSAGE_TYPE, -- event_type
                            @ORC.ORDER_CONTROL, -- order_control_id
                            @PID.PATIENT_ID, -- patient_id
                            @PID.ID_ISSUER_CODE, -- patient_id_issuer_code
                            @PID.FULL_NAME, -- patient_name
                            @PID.FAMILY_NAME, -- last_name
                            @PID.GIVEN_NAME, -- first_name
                            @PID.MIDDLE_NAME, -- middle_name
                            @PID.PREFIX, -- prefix
                            @PID.SUFFIX, -- suffix
                            @PID.DATE_OF_BIRTH, -- patient_birth_dttm
                            @PID.ADMINISTRATIVE_SEX, -- patient_sex
                            @PID.RACE, -- race_code
                            @PID.CONFIDENTIALITY, -- confidentiality
                            @PID.ACCOUNT_NUMBER, -- account_no
                            @PID.ADDRESS, -- address
                            @PV1.PATIENT_CLASS, -- patient_location
                            @PV1.ASSIGNED_PATIENT_LOCATION, -- patient_residence
                            @PV1.ATTENDING_DOCTOR_ID, -- refer_doctor_id
                            @PV1.CONSULTING_DOCTOR_ID, -- consult_doctor_id
                            @OBR.PLACER_ORDER_NUMBER, -- placer_order_id
                            @OBR.FILLER_ORDER_NUMBER, -- filler_order_id
                            @OBR.ACCESSION_NUMBER, -- accession_no
                            @ORC.ORDER_STATUS, -- order_stat
                            @OBR.REASON_FOR_STUDY, -- order_reason
                            @OBR.RELEVANT_CLINICAL_INFORMATION, -- order_comments
                            @OBR.SCHEDULED_DTTM, -- order_dttm
                            @ORC.ORDERING_PROVIDER, -- order_doctor_id
                            @OBR.DIAGNOSTIC_SERV_SECT_ID, -- order_department
                            @ORC.ENTERED_BY, -- order_entry_user_id
                            @ORC.ENTERERS_LOCATION, -- order_entry_location
                            @ORC.CALL_BACK_PHONE_NUMBER, -- order_callback_phone_no
                            null, -- attend_doctor_id
                            null, -- perform_doctor_id
                            '200', -- reqproc_stat
                            @OBR.UNIVERSAL_SERVICE_IDENTIFIER_ID, -- reqproc_id
                            @OBR.UNIVERSAL_SERVICE_IDENTIFIER_TEXT, -- reqproc_desc
                            @OBR.UNIVERSAL_SERVICE_IDENTIFIER_ID, -- reqproc_code_value
                            @OBR.NAME_OF_CODING_SYSTEM, -- reqproc_code_scheme
                            null, -- reqproc_code_version
                            @OBR.UNIVERSAL_SERVICE_IDENTIFIER_TEXT, -- reqproc_code_meaning
                            null, -- study_instance_uid
                            @OBR.REASON_FOR_STUDY, -- reqproc_reason
                            @NTE.COMMENT, -- reqproc_comments
                            @OBR.PRIORITY, -- reqproc_priority
                            null, -- reqproc_location
                            @OBR.TRANSPORT_ARRANGED, -- patient_arrange
                            null, -- diagnosis for ODBC
                            null, -- other_patient_id for ODBC
                            null, -- other_patient_name for ODBC
                            null, -- source_aetitle
                            null, -- broker_aetitle
                            'HL7-PACS', -- broker_type
                            @PID.SSN, -- patient_ssn
                            @DG1.DIAGNOSIS_CODE_ID, -- diagnosis_code
                            @DG1.DIAGNOSIS_CODE_TEXT, -- diagnosis_code_meaning
                            @NTE.COMMENT, -- note_and_comments
                            null, -- sending_facility
                            null, -- patient_weight for ODBC
                            null, -- patient_size for ODBC
                            null, -- vet_sex_neutered
                            null, -- species_code_description
                            null, -- breed_code_description
                            null, -- nk1_name
                            null, -- nk1_relationship
                            null -- nk1_organization_name
                          );

          IF @ORC.ORDER_CONTROL != 'CA' THEN -- order_control_id
            v_msps := @MSPS;
            FOR repeat IN (SELECT trim(REGEXP_SUBSTR(v_msps, '(.*?)(\\R\\|$)', 1, LEVEL, 'c', 1)) as text
                            FROM dual
                            CONNECT BY LEVEL < REGEXP_COUNT(v_msps, '(.*?)(\\R\\|$)'))
            LOOP
              v_reqproc_code_value := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 1, 'c', 1));
              v_reqproc_code_scheme := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 2, 'c', 1));
              v_sps_id := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 3, 'c', 1));
              v_modality := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 4, 'c', 1));
              v_sps_start_dttm := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 5, 'c', 1));
              v_protcode_value := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 6, 'c', 1));
              v_protcode_scheme := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 7, 'c', 1));
              v_protcode_meaning := trim(REGEXP_SUBSTR(repeat.text, '(.*?)(\\F\\|$)', 1, 8, 'c', 1));
            
              CONTINUE WHEN v_prior_sps_id = v_sps_id;
            
              v_msps_key := sp_mapper.put_msps(
                              v_study_key, -- study_key
                              v_reqproc_code_value, -- reqproc_code_value
                              v_reqproc_code_scheme, -- reqproc_code_scheme
                              v_sps_id, -- sps_id
                              v_modality, -- modality
                              v_sps_start_dttm, -- sps_start_dttm
                              v_protcode_value, -- protcode_value
                              v_protcode_scheme, -- protcode_scheme
                              v_protcode_meaning, -- protcode_meaning
                              v_idx, -- index
                              null, -- aetitle
                              null, -- scheduled_location
                              'HL7-PACS', -- broker_type : 'HL7-PACS' = PACS Only, 'HL7-IHE' = RIS & PACS
                              @ORC.ORDER_CONTROL, -- order_control_id
                              @ORC.ORDER_STATUS -- order_stat
                            );
                v_idx := v_idx + 1;
                v_prior_sps_id := v_sps_id;
            END LOOP;
          END IF;
        END;

      
        DECLARE
          v_study_key NUMBER;
          v_msps_key NUMBER;
        BEGIN
          v_study_key := sp_mapper.put_appointment(
                            @MSH.MESSAGE_TYPE, -- event_type
                            null, -- order_control_id
                            @PID.PATIENT_ID, -- patient_id
                            @PID.ID_ISSUER_CODE, -- patient_id_issuer_code
                            @PID.FULL_NAME, -- patient_name
                            @PID.FAMILY_NAME, -- last_name
                            @PID.GIVEN_NAME, -- first_name
                            @PID.MIDDLE_NAME, -- middle_name
                            @PID.PREFIX, -- prefix
                            @PID.SUFFIX, -- suffix
                            @PID.DATE_OF_BIRTH, -- patient_birth_dttm
                            @PID.ADMINISTRATIVE_SEX, -- patient_sex
                            @PID.RACE, -- race_code
                            @PID.CONFIDENTIALITY, -- confidentiality
                            @PID.ACCOUNT_NUMBER, -- account_no
                            @PID.ADDRESS, -- address
                            @PV1.PATIENT_CLASS, -- patient_location
                            @PV1.ASSIGNED_PATIENT_LOCATION, -- patient_residence
                            @PV1.ATTENDING_DOCTOR_ID, -- refer_doctor_id
                            @PV1.CONSULTING_DOCTOR_ID, -- consult_doctor_id
                            @SCH.PLACER_APPOINTMENT_ID, -- placer_order_id
                            null, -- filler_order_id
                            @SCH.PLACER_APPOINTMENT_ID, -- accession_no
                            null, -- order_stat
                            null, -- order_reason
                            null, -- order_comments
                            null, -- order_dttm
                            @AIP.PERSONNEL_RESOURCE_ID_ID_NUMBER, -- order_doctor_id
                            @AIP.PERSONNEL_RESOURCE_ID_FAMILY_NAME, -- order_doctor_last_name
                            @AIP.PERSONNEL_RESOURCE_ID_GIVEN_NAME, -- order_doctor_first_name
                            'MDEM', -- order_department
                            null, -- order_entry_user_id
                            null, -- order_entry_location
                            null, -- order_callback_phone_no
                            '200', -- reqproc_stat
                                
                            null, -- reqproc_id
                            null, -- reqproc_desc
                            @SCH.EVENT_REASON_IDENTIFIER, -- reqproc_code_value
                            @SCH.EVENT_REASON_NAME_OF_CODING_SYSTEM, -- reqproc_code_scheme
                            null, -- reqproc_code_version
                            @SCH.EVENT_REASON_TEXT, -- reqproc_code_meaning
                            null, -- study_instance_uid
                            @SCH.APPOINTMENT_REASON_TEXT, -- reqproc_reason
                            null, -- reqproc_comments
                            null, -- reqproc_priority
                            null, -- reqproc_location
                            null -- patient_arrange
                          );

            IF @MSH.MESSAGE_TYPE != 'SIU^S15' THEN
              v_msps_key := sp_mapper.put_msps(
                            v_study_key, -- study_key
                            @SCH.EVENT_REASON_IDENTIFIER, -- reqproc_code_value
                            @SCH.EVENT_REASON_NAME_OF_CODING_SYSTEM, -- reqproc_code_scheme
                            @SCH.PLACER_APPOINTMENT_ID, -- sps_id
                            'CR', -- modality
                            @SCH.APPOINTMENT_TIMING_QUANTITY, -- sps_start_dttm
                            @SCH.EVENT_REASON_IDENTIFIER, -- protcode_value
                            'CPT', -- protcode_scheme
                            @SCH.EVENT_REASON_TEXT, -- protcode_meaning
                            1, -- index
                            null, -- aetitle
                            null, -- scheduled_location
                            'HL7-PACS', -- broker_type : 'HL7-PACS' = PACS Only, 'HL7-IHE' = RIS & PACS
                            null, -- order_control_id
                            null -- order_stat
                          );
            END IF;
        END;


  DECLARE
    v_mdm_key NUMBER;
  BEGIN
    v_mdm_key := sp_mapper.put_document(
                      @MSH.MESSAGE_TYPE, -- event_type
                      @MSH.PROCESSING_ID, -- processing_id
                      @PID.PATIENT_ID, -- patient_id
                      @PID.ID_ISSUER_CODE, -- patient_id_issuer_code
                      @PID.FULL_NAME, -- patient_name
                      @PID.FAMILY_NAME, -- last_name
                      @PID.GIVEN_NAME, -- first_name
                      @PID.MIDDLE_NAME, -- middle_name
                      @PID.PREFIX, -- prefix
                      @PID.SUFFIX, -- suffix
                      @PID.DATE_OF_BIRTH, -- patient_birth_dttm
                      @PID.ADMINISTRATIVE_SEX, -- patient_sex
                      @PID.RACE, -- race_code
                      @PID.ACCOUNT_NUMBER, -- account_no
                      @PID.SSN, -- patient_ssn
                      @PV1.PATIENT_CLASS, -- patient_location
                      @PV1.ASSIGNED_PATIENT_LOCATION, -- patient_residence
                      @PV1.ATTENDING_DOCTOR_ID, -- refer_doctor_id
                      @PV1.REFERRING_DOCTOR_NAME, -- refer_doctor_name
                      @PV1.CONSULTING_DOCTOR_ID, -- consult_doctor_id
                      @PV1.VISIT_NUMBER, -- visit_number
                      @MSH.VISIT_STATUS, -- visit_stat
                      @PV1.ADMIT_DTTM, -- admit_dttm
                      null, -- doc_type
                      null, -- doc_contentpresentation
                      @TXA.ACTIVITY_DATE_TIME, -- activity_dttm
                      null, -- primary_code_name
                      @TXA.ORIGINATION_DATE_TIME, -- origination_dttm
                      @TXA.TRANSCRIPTION_DATE_TIME, -- transcription_dttm
                      @TXA.EDIT_DATE_TIME, -- edit_dttm
                      @TXA.ORIGINATOR_CODE_NAME, -- originator_code_name
                      @TXA.ASSIGNED_DOCUMENT_AUTHENTICATOR, -- assigneddoc_authenticator
                      @TXA.TRANSCRIPTIONIST_CODE_NAME, -- transcriptionist_code_name
                      @TXA.UNIQUE_DOCUMENT_NUMBER, -- unique_doc_number
                      @TXA.PARENT_DOCUMENT_NUMBER, -- parent_doc_number
                      @TXA.PLACER_ORDER_NUMBER, -- placer_order_number
                      @TXA.FILLER_ORDER_NUMBER, -- filler_order_number
                      @TXA.UNIQUE_DOCUMENT_FILE_NAME, -- uniquedoc_file_name
                      @TXA.DOCUMENT_COMPLETION_STATUS, -- doc_completion_status
                      @TXA.DOCUMENT_CONFIDENTIALITY_STATUS, -- doc_confidentiality_status
                      @TXA.DOCUMENT_AVAILABILITY_STATUS, -- doc_availability_status
                      @TXA.DOCUMENT_STORAGE_STATUS, -- doc_storage_status
                      @TXA.DOCUMENT_CHANGE_REASON, -- doc_change_reason
                      @TXA.AUTHENTICATION_PERSON_TIME_STAMP, -- authentication_time_stamp
                      null, -- distributed_code_name
                      'HL7-PACS' -- broker_type
                    );
  END;

      
        DECLARE
          v_report_key NUMBER;
          v_text       CLOB := $OBX.OBSERVATION_VALUE_TEXT;
          v_len        NUMBER := DBMS_LOB.getlength(v_text);
          v_pos        NUMBER := 1;
          v_chunk      VARCHAR2(32767);
          v_IsFirstReport   VARCHAR2(10) := 'TRUE';
        BEGIN
          WHILE v_pos <= v_len LOOP

            -- Get the chunk of report_text (amount must be less than or equal to 32767)
            v_chunk := DBMS_LOB.SUBSTR(v_text, 4000, v_pos); 
            
            -- G3 broker calls put_report in 4000 character units(HL7). If report_interface_type = 'INA' and v_text is larger than 32768 put_report is failed.
            v_report_key := sp_mapper.put_report(
                              @MSH.MESSAGE_TYPE, -- event_type
                              'NM', -- report_control_id
                              @OBR.ACCESSION_NUMBER, -- accession_no
                              @PID.PATIENT_ID, -- patient_id
                              @OBX.OBSERVATION_RESULT_STATUS, -- report_stat
                              NULL, -- creator_id
                              NULL, -- creator_name
                              @OBX.DTTM_OF_THE_OBSERVATION, -- create_dttm
                              NULL, -- dictator_id
                              NULL, -- dictator_name
                              @OBX.DTTM_OF_THE_OBSERVATION, -- dictate_dttm
                              @OBX.RESPONSIBLE_OBSERVER.ID_NUMBER, -- transcriber_id
                              @OBX.RESPONSIBLE_OBSERVER.NAME, -- transcriber_name
                              @OBX.DTTM_OF_THE_OBSERVATION, -- transcribe_dttm
                              @OBR.PRINCIPAL_RESULT_INTERPRETER, -- approver_id
                              @OBX.RESPONSIBLE_OBSERVER.NAME, -- approver_name
                              @OBX.RESULTS_REPORT_STATUS_CHANGE_DTTM, -- approve_dttm
                              NULL, -- reviser_id
                              NULL, -- reviser_name
                              @OBX.DTTM_OF_THE_OBSERVATION, -- revise_dttm
                              NULL, -- report_type
                              v_chunk, -- report_text
                              NULL, -- conclusion
                              'HL7-PACS', -- broker_type
                              'General', -- report_interface_type ('General' or 'INA')
                              v_IsFirstReport -- IsFirstReport
                            );
            
            -- Change to false after the first chunk
            v_IsFirstReport := 'FALSE';
             -- Next chunk start position (in characters)
            v_pos := v_pos + LENGTH(v_chunk);
          END LOOP;
        END;

      
        DECLARE
            v_user_key NUMBER;
        BEGIN
            v_user_key := sp_mapper.put_user(
                    @USER_ID, -- user_id
                    @USER_NAME, -- user_name
                    @USER_PASSWORD, -- password
                    @USER_LEVEL, -- user_level
                    @USER_STATUS, -- user_status
                    @USER_COMMENT, -- user_comment
                    @USER_HYUSER_KEY -- hyuser_key
                );
        END;
